async function getRecommendations(userId) {
  const [userHistory, topPosts] = await Promise.all([
    db.history.findMany({ where: { userId }, select: { postId: true }, take: 100 }),
    db.posts.findMany({ orderBy: { score: 'desc' }, take: 50, select: { id: true, title: true, slug: true, score: true } }),
  ]);
  const seen = new Set(userHistory.map(h => h.postId));
  return topPosts.filter(p => !seen.has(p.id)).slice(0, 10);
}
